import { css, property, state, customElement, html } from "@umbraco-cms/backoffice/external/lit";
import { UmbLitElement } from "@umbraco-cms/backoffice/lit-element";
import { UmbTextStyles } from "@umbraco-cms/backoffice/style";

@customElement("custom-text-editor")
export default class CustomTextEditorElement extends UmbLitElement {
  
  @property({ type: String })
  value = "";

  @property({ attribute: false })
  config: any;

  @state()
  _maxLength: number | null = null;

  @state()
  _placeholder: string | null = null;

  connectedCallback() {
    super.connectedCallback();
    this._updateConfigValues();
  }

  render() {
    const length = this.value?.length || 0;
    const hasMax = this._maxLength && this._maxLength > 0;

    let status = "";

    if (this._maxLength) {
      if (length > this._maxLength * 0.9) {
        status = "danger";
      } else if (length > this._maxLength * 0.7) {
        status = "warning";
      }
    }

    return html`
      <uui-input
        class="text-input"
        type="text"
        .value=${this.value || ""}
        .placeholder=${this._placeholder || ""}
        .maxlength=${this._maxLength || ""}
        @input=${this._onInput}
      ></uui-input>

      ${hasMax
        ? html`
            <div class="char-counter ${status}">
              ${length}/${this._maxLength}
            </div>
          `
        : ""}
    `;
  }

  _updateConfigValues() {
    this._maxLength = this.config?.getValueByAlias("maxChars");
    this._placeholder =
      this.config?.getValueByAlias("placeholder") || "Enter text here...";
  }

  _onInput(event: any) {
    const input = event.target;
    const newValue = input.value;

    if (this._maxLength && newValue.length > this._maxLength) {
      input.value = this.value;
      return;
    }

    this.value = newValue;
    this._dispatchChangeEvent();
  }

  _dispatchChangeEvent() {
    this.dispatchEvent(
      new CustomEvent("change", {
        detail: { value: this.value },
        bubbles: true,
        composed: true,
      })
    );
  }

  static styles = [
    UmbTextStyles,
    css`
      .text-input {
        width: 100%;
      }

      .char-counter {
        position: absolute;
        bottom: -20px;
        right: 0;
        font-size: 12px;
        color: var(--uui-color-text-alt);
      }

      .char-counter.warning {
        color: var(--uui-color-warning);
      }

      .char-counter.danger {
        color: var(--uui-color-danger);
      }
    `,
  ];
}